# MCP uses JSON-RPC 2.0. The first message after connecting is always "initialize".
# Client sends:
{
  "jsonrpc": "2.0",
  "id": 1,
  "method": "initialize",
  "params": {
    "protocolVersion": "2024-11-05",
    "capabilities": { "tools": {} },
    "clientInfo": { "name": "my-agent", "version": "1.0.0" }
  }
}

# Server responds with its capabilities:
{
  "jsonrpc": "2.0",
  "id": 1,
  "result": {
    "protocolVersion": "2024-11-05",
    "capabilities": {
      "tools": { "listChanged": true },
      "resources": { "subscribe": false }
    },
    "serverInfo": { "name": "github-mcp-server", "version": "0.6.2" }
  }
}

# Client: list available tools
{ "jsonrpc":"2.0","id":2,"method":"tools/list","params":{} }

# Server response:
{
  "jsonrpc":"2.0","id":2,"result":{
    "tools":[
      {
        "name":"list_pull_requests",
        "description":"List open pull requests for a GitHub repository.",
        "inputSchema":{
          "type":"object",
          "properties":{
            "owner":{"type":"string","description":"Repository owner"},
            "repo":{"type":"string","description":"Repository name"},
            "state":{"type":"string","enum":["open","closed","all"],"default":"open"}
          },
          "required":["owner","repo"]
        }
      }
    ]
  }
}

# Client: call a tool
{
  "jsonrpc":"2.0","id":3,"method":"tools/call",
  "params":{
    "name":"list_pull_requests",
    "arguments":{"owner":"anthropics","repo":"claude-code","state":"open"}
  }
}

# Server response (content is a list of content blocks):
{
  "jsonrpc":"2.0","id":3,"result":{
    "content":[
      {"type":"text","text":"PR #42: Add streaming support (opened 2 days ago)"},
      {"type":"text","text":"PR #41: Fix token counting edge case (opened 5 days ago)"}
    ],
    "isError": false
  }
}

import subprocess, json, threading

class MCPClient:
    def __init__(self, command: list[str]):
        self._proc = subprocess.Popen(
            command,
            stdin=subprocess.PIPE,
            stdout=subprocess.PIPE,
            stderr=subprocess.DEVNULL,
            text=True,
        )
        self._id = 0
        self._lock = threading.Lock()
        self._initialize()

    def _next_id(self) -> int:
        self._id += 1
        return self._id

    def _send(self, method: str, params: dict) -> dict:
        with self._lock:
            msg = json.dumps({"jsonrpc":"2.0","id":self._next_id(),"method":method,"params":params})
            self._proc.stdin.write(msg + "\n")
            self._proc.stdin.flush()
            line = self._proc.stdout.readline()
        return json.loads(line).get("result", {})

    def _initialize(self):
        self._send("initialize", {
            "protocolVersion": "2024-11-05",
            "capabilities": {"tools": {}},
            "clientInfo": {"name": "my-agent", "version": "1.0.0"},
        })

    def list_tools(self) -> list[dict]:
        result = self._send("tools/list", {})
        return [
            {
                "name": t["name"],
                "description": t.get("description",""),
                "input_schema": t.get("inputSchema", {"type":"object","properties":{}}),
            }
            for t in result.get("tools", [])
        ]

    def call_tool(self, name: str, arguments: dict) -> str:
        result = self._send("tools/call", {"name": name, "arguments": arguments})
        content = result.get("content", [])
        return "\n".join(c.get("text","") for c in content if c.get("type")=="text")

    def close(self):
        self._proc.stdin.close()
        self._proc.wait()

# Usage:
# client = MCPClient(["npx", "-y", "@modelcontextprotocol/server-github"])
# tools = client.list_tools()
# result = client.call_tool("list_pull_requests", {"owner": "anthropics", "repo": "sdk-python"})

import anthropic

claude = anthropic.Anthropic()

def run_agent(mcp_client: MCPClient, user_message: str) -> str:
    tools = mcp_client.list_tools()
    messages = [{"role": "user", "content": user_message}]

    while True:
        resp = claude.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=2048,
            tools=tools,
            messages=messages,
        )

        if resp.stop_reason == "end_turn":
            return next(b.text for b in resp.content if hasattr(b, "text"))

        if resp.stop_reason != "tool_use":
            break

        tool_results = []
        for block in resp.content:
            if block.type != "tool_use":
                continue
            result_text = mcp_client.call_tool(block.name, block.input)
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": result_text,
            })

        messages.append({"role": "assistant", "content": resp.content})
        messages.append({"role": "user", "content": tool_results})

    return "Loop ended."

# Resources expose read-only data (files, DB rows, API responses) as URIs.
# Client lists available resources:
{ "jsonrpc":"2.0","id":4,"method":"resources/list","params":{} }

# Response:
{
  "result":{
    "resources":[
      {
        "uri": "file:///project/README.md",
        "name": "README",
        "mimeType": "text/markdown"
      },
      {
        "uri": "postgres://db/customers?limit=10",
        "name": "Recent Customers",
        "mimeType": "application/json"
      }
    ]
  }
}

# Client reads a resource:
{
  "jsonrpc":"2.0","id":5,"method":"resources/read",
  "params":{"uri":"file:///project/README.md"}
}

# Prompts: reusable prompt templates exposed by a server
# List available prompts:
{ "jsonrpc":"2.0","id":6,"method":"prompts/list","params":{} }

# Response:
{
  "result":{
    "prompts":[
      {
        "name":"summarize_pr",
        "description":"Summarize a GitHub pull request.",
        "arguments":[{"name":"pr_number","required":true}]
      }
    ]
  }
}

# Get a prompt (server fills in template with the given arguments):
{ "jsonrpc":"2.0","id":7,"method":"prompts/get",
  "params":{"name":"summarize_pr","arguments":{"pr_number":"42"}} }

# Response:
{
  "result":{
    "messages":[
      {
        "role":"user",
        "content":{"type":"text","text":"Summarize PR #42: Add streaming support..."}
      }
    ]
  }
}
